code = """import json, re, pandas as pd

def load_maybe_path(x):
    if isinstance(x, str):
        with open(x, 'r', encoding='utf-8') as f:
            return json.load(f)
    return x

papers = load_maybe_path(var_call_mQ4MR4okAGVk8rRwsPEjOnVV)

df = pd.DataFrame(papers)
df['title'] = df['filename'].str.replace(r'\\.txt$', '', regex=True)

pattern = re.compile(r"\b(?:CHI|UbiComp|CSCW|DIS|IUI|WWW|TEI|OzCHI|PervasiveHealth|AH)\s*'?\s*(\d{2})\b")

def get_year(txt):
    if not isinstance(txt, str):
        return None
    m = pattern.search(txt[:2000])
    if m:
        return 2000 + int(m.group(1))
    # look for " 2016 " in first 2000
    return 2016 if re.search(r'\b2016\b', txt[:2000]) else None

df['pub_year'] = [get_year(t) for t in df['text'].tolist()]

out = df[['title','pub_year']].to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out))"""

